  for (let num of arr) {
    // Perform binary search to find the index of the smallest number in dp
    // which is greater than or equal to num
    let left = 0, right = dp.length;
    while (left < right) {
      const mid = Math.floor((left + right) / 2);
      if (dp[mid] < num) {
        left = mid + 1;
      } else {
        right = mid;
      }
